(()=>{const randomInt=(from,until)=>Math.floor(Math.random()*(until-from+1))+from;const drawOption=options=>{const totalProb=Object.values(options).reduce(((acc,prob)=>acc+prob),0);if(Math.abs(totalProb-1)>1e-8){throw new Error("Total probability does not sum to 1")}const cumProbs=[];let acc=0;for(const prob of Object.values(options)){acc+=prob;cumProbs.push(acc)}const randVal=Math.random();const idx=cumProbs.findIndex((prob=>prob>randVal));const result=Object.keys(options)[idx];return result};setup.drawOption=drawOption;window.drawOption=window.drawOption||drawOption;setup.randomInt=randomInt;window.randomInt=window.randomInt||randomInt})();
/* Random 工具 */